  ('pukao-1fb53453-moex-00351', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '當公共支出計畫案的總利益現值等同於總成本現值時，其折現率即為：', '["實質利率", "外部報酬率", "內部報酬率", "名目利率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
